// A10 loop body, per the draft's own accepted derivation:
loop {
  let k = next_k();
  let e = t.entry(k);   // state gains binding e: confined, src(e)={t}, L(t)={unique:e}
  e.fill(v);            // e consumed-flag = true, L(t)={}
  match done() {
    T => { break; }     // break state CONTAINS e (consumed-flag true); loop-entry state has no binding e at all
    F => { noop(); }
  }
}

fn main() {
  let t1: table<K,V> = table.new();
  let e1 = t1.entry(k1);   // L(t1)={unique:e1}; region of e1 = main block
  e1.fill(v1);             // e1 consumed, L(t1)={}
  let t2: table<K,V> = table.new();
  let e2 = t2.entry(k2);   // L(t2)={unique:e2}; same block region, so entry types are identical
  e1 = e2;                 // TOK-4: destination consumed + identical type => legal move; loans rename: L(t2)={unique:e1}
}
// Scope end, LOAN-5 reverse binding order (t1,e1,t2,e2 reversed): drop e2 (consumed, no-op),
// drop t2 while L(t2)={unique:e1} is LIVE, then auto-consume e1 — its drop obligation
// (entry finalize) runs against t2's freed storage.

confined struct Env<'e> { t: &'e table<K,V> }
fn body(chunk: &uniq 'c chunk<i64>, env: &'e Env<'e>) reads('e) writes('c) {
  let v = env.t.get(k);   // draft P6's own body line: projects borrow field t out of a
                          // &-borrowed user-declared confined struct and calls through it —
                          // LOAN-2a covers construction only; TOK-4 covers whole-binding borrows/moves;
                          // NO rule types field projection
}

confined enum lock_result<'m> { Got(guard<'m>), Busy }  // needed because option<guard<'m>> is ill-formed by TOK-1 post-mono
fn worker(m: &'a mutex<St>) {
  loop {
    let r = m.try_lock();        // try_lock<'m>(&'m mutex<St>) -> lock_result<'m>: shared issue on m held by r
    match r {                    // extracting Got(g) moves a confined value out of an enum: loan renaming at arm bindings is unspecified
      Got(g) => { break; }       // break state L(m)={shared:g}, g live != loop entry {} -> LOAN-8 REJECT
      Busy   => { spin_hint(); } // and the two arms end in different states -> LOAN-8 REJECT again
    }
  }
  // the guard cannot be held past the loop under any restructuring
}

